Y3bBzRNTckQyg0av.command:
const selected = await DC20.dialog.SimplePopup.select("Select Elemental Type", {fire: "Fire", earth: "Earth", air: "Air", water: "Water"});
if (!selected) return;

// Select natural weapon damage
const naturalWeapon = actor.getItemByKey("naturalWeapon");
if (naturalWeapon) {
  const damageType = selected === "fire" ? "fire" : (await DC20.dialog.SimplePopup.select("Select Damage Type", getDamageOptions(selected)) || "fire");
  naturalWeapon.update({["system.formulas.SaJkGgLYTVwarjUP.type"]: damageType});
}

// Set effect
const effect = item.effects.get("bwOgUaMeRa8UH14J");
if (effect) {
  const changes = [];
  setChanges(selected, changes);
  effect.update({changes: changes});
}

// Set attributes
switch (selected) {
  case "fire": case "air":
    actor.update({
      ["system.attributes.mig.current"]: 1,
      ["system.attributes.agi.current"]: 3,
    })
    break;

  case "earth": case "water":
    actor.update({
      ["system.attributes.mig.current"]: 3,
      ["system.attributes.agi.current"]: 1,
    })
    break;
}

function getDamageOptions(selected) {
  switch (selected) {
    case "earth": return {bludgeoning: "Bludgeoning", piercing: "Piercing"}
    case "air":   return {lightning: "Lightning", slashing: "Slashing" }
    case "water": return {cold: "Cold", corrosion: "Corrosion"}
  }
}

function setChanges(selected, changes) {
  switch (selected) {
    case "fire":  
      changes.push({key: "system.damageReduction.damageTypes.fire.resistance", mode: 5, value: true});
      break;

    case "earth": 
      changes.push(
        {key: "system.damageReduction.pdr.active", mode: 5, value: true},
        {key: "system.movement.burrow.fullSpeed", mode: 5, value: true},
        {key: "system.senses.tremorsense.range", mode: 5, value: 3}
      )
      break;

    case "air":   
      changes.push(
        {key: "system.damageReduction.damageTypes.lightning.resistance", mode: 5, value: true},
        {key: "system.jump.bonus", mode: 2, value: 5},
      )
      break;

    case "water": 
      changes.push(
        {key: "system.damageReduction.damageTypes.cold.resistance", mode: 5, value: true},
        {key: "system.damageReduction.damageTypes.corrosion.resistance", mode: 5, value: true},
        {key: "system.movement.swimming.fullSpeed", mode: 5, value: true},
      )
      break;
  }
}
